/// Result of a visitor callback.
///
/// Allows visitors to control the conversion flow by either proceeding
/// with default behavior, providing custom output, skipping elements,
/// preserving HTML, or signaling errors.
public enum VisitResult {
    /// Continue with default conversion behavior
    case continue_
    /// Replace default output with custom markdown
    ///
    /// The visitor takes full responsibility for the markdown output
    /// of this node and its children.
    case custom(field0: String)
    /// Skip this element entirely (don't output anything)
    ///
    /// The element and all its children are ignored in the output.
    case skip
    /// Preserve original HTML (don't convert to markdown)
    ///
    /// The element's raw HTML is included verbatim in the output.
    case preserveHtml
    /// Stop conversion with an error
    ///
    /// The conversion process halts and returns this error message.
    case error(field0: String)
}

/// Errors that can occur during HTML to Markdown conversion.
public enum ConversionError: Swift.Error {
    /// HTML parsing error
    case parseError(message: String, field0: String)
    /// HTML sanitization error
    case sanitizationError(message: String, field0: String)
    /// Invalid configuration
    case configError(message: String, field0: String)
    /// I/O error
    case ioError(message: String, field0: String)
    /// Panic caught during conversion to prevent unwinding across FFI boundaries
    case panic(message: String, field0: String)
    /// Invalid input data
    case invalidInput(message: String, field0: String)
    /// Generic conversion error
    case other(message: String, field0: String)
}

